INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("ＴＰダウンカット", "バトル開始時、すべてのモンスターがＴＰダウン\n50％カット状態になる。", 10011005, 4100110, "boss_tp_down_cut");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("ＴＰ上昇ダウン", "バトル開始時、すべてのキャラのＴＰ上昇を中ダウンさせる。", 10011006, 4100110, 3);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("ＨＰ吸収ダウン", "バトル開始時、すべてのキャラのＨＰ吸収を特大ダウンさせる。", 10011007, 4100110, 9);
